  case 'excel':
    $initial=ob_get_level();ob_start();require_once "../../inc/lib/PHPExcel.php";require_once "../../inc/excel_style_helper.php";PHPExcel_Shared_File::setUseUploadTempDirectory(true);$from=isset($_GET['tgl_awal'])?$_GET['tgl_awal']:date('Y-m-d');$to=isset($_GET['tgl_akhir'])?$_GET['tgl_akhir']:date('Y-m-d');$status=isset($_GET['status'])?trim($_GET['status']):'';$plant=isset($_GET['plant'])?trim($_GET['plant']):'';$p=array($from,$to);$w=" WHERE p.status IN ('RELEASED','IN_PROCESS','CONFIRMED') AND p.start_date BETWEEN ? AND ? ";if($status!==''){$w.=" AND p.status=? ";$p[]=$status;}if($plant!==''){$w.=" AND p.plant=? ";$p[]=$plant;}
