    $excel=new PHPExcel();$sh=$excel->setActiveSheetIndex(0);$sh->setTitle(erp_export_sheet_title('My Orders'));$heads=array(erp_export_label("No"),erp_export_label("Production Order"),erp_export_label("Status"),erp_export_label("Priority"),erp_export_label("Strategy"),erp_export_label("Plant"),erp_export_label("Material"),erp_export_label("Order Qty"),erp_export_label("UOM"),erp_export_label("Start"),erp_export_label("Finish"),erp_export_label("Required Mat"),erp_export_label("Issued Mat"),erp_export_label("Material %"),erp_export_label("Yield"),erp_export_label("Confirm %"),erp_export_label("Scrap"),erp_export_label("Downtime Min"));foreach($heads as $i=>$v)$sh->setCellValue(PHPExcel_Cell::stringFromColumnIndex($i).'4',$v);$r=5;$n=1;foreach($rows as $row){$vals=array($n++,$row->no_production_order,$row->status,$row->priority,$row->order_strategy,$row->plant,$row->material_code.' - '.$row->material_name,(float)$row->order_qty,$row->uom,$row->start_date,$row->finish_date,(float)$row->required_qty,(float)$row->issued_qty,mpoa_pct($row->issued_qty,$row->required_qty),(float)$row->yield_qty,mpoa_pct($row->yield_qty,$row->order_qty),(float)$row->conf_scrap_qty,(float)$row->downtime_minutes);foreach($vals as $i=>$v)$sh->setCellValue(PHPExcel_Cell::stringFromColumnIndex($i).$r,$v);$r++;}
